For microservices handling multiple message types, you need a type-safe dispatcher pattern that avoids dynamic type registration while still supporting extensibility. The key is using an envelope pattern with explicit type mapping and validation.

**PRODUCTION PATTERN**:

```go
package main

import (
	"context"
	"crypto/hmac"
	"crypto/sha256"
	"encoding/hex"
	"encoding/json"
	"errors"
	"fmt"
	"io"
	"log/slog"
	"net/http"
	"sync"
	"time"

	"github.com/go-playground/validator/v10"
)

const (
	MaxBodySize        = 1 << 20 // 1MB
	MaxProcessingTime  = 30 * time.Second
	SignatureHeader    = "X-Message-Signature"
	TimestampHeader    = "X-Message-Timestamp"
	MaxTimestampSkew   = 5 * time.Minute
)

var (
	ErrUnknownMessageType = errors.New("unknown message type")
	ErrInvalidSignature   = errors.New("invalid message signature")
	ErrTimestampExpired   = errors.New("message timestamp expired")
	ErrValidationFailed   = errors.New("message validation failed")
)

// Message envelope with type discriminator
type MessageEnvelope struct {
	Type      string          `json:"type" validate:"required,alpha,max=50"`
	Version   string          `json:"version" validate:"required,semver"`
	Timestamp int64           `json:"timestamp" validate:"required"`
	Payload   json.RawMessage `json:"payload" validate:"required"`
}

// Concrete message types - all strongly typed
type OrderCreatedMessage struct {
	OrderID    string  `json:"order_id" validate:"required,uuid"`
	CustomerID string  `json:"customer_id" validate:"required,uuid"`
	Amount     float64 `json:"amount" validate:"required,gt=0,lt=1000000"`
	Currency   string  `json:"currency" validate:"required,len=3,alpha"`
}

type UserRegisteredMessage struct {
	UserID string `json:"user_id" validate:"required,uuid"`
	Email  string `json:"email" validate:"required,email,max=255"`
	Role   string `json:"role" validate:"required,oneof=user admin moderator"`
}

type PaymentProcessedMessage struct {
	PaymentID     string  `json:"payment_id" validate:"required,uuid"`
	OrderID       string  `json:"order_id" validate:"required,uuid"`
	Amount        float64 `json:"amount" validate:"required,gt=0"`
	Status        string  `json:"status" validate:"required,oneof=success failed pending"`
	TransactionID string  `json:"transaction_id" validate:"required,alphanum,max=64"`
}

// Type-safe message handler interface
type MessageHandler[T any] interface {
	Handle(ctx context.Context, msg T) error
}

// Secure message dispatcher with compile-time type safety
type SecureDispatcher struct {
	validator    *validator.Validate
	logger       *slog.Logger
	signingKey   []byte
	handlersMu   sync.RWMutex
	handlers     map[string]func(context.Context, json.RawMessage) error
	allowedTypes map[string]bool
	metrics      *DispatcherMetrics
}

type DispatcherMetrics struct {
	messagesProcessed int64
	messagesFailed    int64
	signatureFailures int64
}

func NewSecureDispatcher(signingKey []byte, logger *slog.Logger) *SecureDispatcher {
	d := &SecureDispatcher{
		validator:    validator.New(),
		logger:       logger,
		signingKey:   signingKey,
		handlers:     make(map[string]func(context.Context, json.RawMessage) error),
		allowedTypes: make(map[string]bool),
		metrics:      &DispatcherMetrics{},
	}

	// SECURE: Explicitly register allowed message types at startup
	d.registerHandler("order_created", handleTypedMessage[OrderCreatedMessage])
	d.registerHandler("user_registered", handleTypedMessage[UserRegisteredMessage])
	d.registerHandler("payment_processed", handleTypedMessage[PaymentProcessedMessage])

	return d
}

// Generic handler factory - ensures type safety at compile time
func handleTypedMessage[T any](ctx context.Context, payload json.RawMessage) error {
	var msg T
	if err := json.Unmarshal(payload, &msg); err != nil {
		return fmt.Errorf("unmarshal payload: %w", err)
	}
	// Process the strongly-typed message
	return processMessage(ctx, msg)
}

func processMessage[T any](ctx context.Context, msg T) error {
	// Type-specific processing logic
	slog.Info("Processing message", "type", fmt.Sprintf("%T", msg))
	return nil
}

func (d *SecureDispatcher) registerHandler(
	msgType string,
	handler func(context.Context, json.RawMessage) error,
) {
	d.handlersMu.Lock()
	defer d.handlersMu.Unlock()
	d.handlers[msgType] = handler
	d.allowedTypes[msgType] = true
}

// SECURE: Verify message signature before processing
func (d *SecureDispatcher) verifySignature(body []byte, signature string, timestamp int64) error {
	// Check timestamp to prevent replay attacks
	msgTime := time.Unix(timestamp, 0)
	if time.Since(msgTime).Abs() > MaxTimestampSkew {
		d.metrics.signatureFailures++
		return ErrTimestampExpired
	}

	// Compute expected signature
	mac := hmac.New(sha256.New, d.signingKey)
	mac.Write(body)
	mac.Write([]byte(fmt.Sprintf("%d", timestamp)))
	expectedSig := hex.EncodeToString(mac.Sum(nil))

	// Constant-time comparison
	if !hmac.Equal([]byte(signature), []byte(expectedSig)) {
		d.metrics.signatureFailures++
		return ErrInvalidSignature
	}

	return nil
}

// Main HTTP handler with full security controls
func (d *SecureDispatcher) HandleMessage(w http.ResponseWriter, r *http.Request) {
	ctx, cancel := context.WithTimeout(r.Context(), MaxProcessingTime)
	defer cancel()

	// LAYER 1: Size limiting
	r.Body = http.MaxBytesReader(w, r.Body, MaxBodySize)
	body, err := io.ReadAll(r.Body)
	if err != nil {
		d.logger.Warn("Body read failed", "error", err, "remote", r.RemoteAddr)
		http.Error(w, "Request too large", http.StatusRequestEntityTooLarge)
		return
	}

	// LAYER 2: Signature verification
	signature := r.Header.Get(SignatureHeader)
	timestamp := r.Header.Get(TimestampHeader)
	var ts int64
	fmt.Sscanf(timestamp, "%d", &ts)

	if err := d.verifySignature(body, signature, ts); err != nil {
		d.logger.Warn("Signature verification failed",
			"error", err,
			"remote", r.RemoteAddr,
		)
		http.Error(w, "Unauthorized", http.StatusUnauthorized)
		return
	}

	// LAYER 3: Parse envelope only
	var envelope MessageEnvelope
	decoder := json.NewDecoder(r.Body)
	decoder.DisallowUnknownFields()

	if err := json.Unmarshal(body, &envelope); err != nil {
		d.logger.Warn("Invalid envelope format", "error", err, "remote", r.RemoteAddr)
		http.Error(w, "Invalid message format", http.StatusBadRequest)
		return
	}

	// LAYER 4: Validate envelope
	if err := d.validator.Struct(envelope); err != nil {
		d.logger.Warn("Envelope validation failed", "error", err)
		http.Error(w, "Invalid message envelope", http.StatusBadRequest)
		return
	}

	// LAYER 5: Allowlist check for message type
	d.handlersMu.RLock()
	handler, exists := d.handlers[envelope.Type]
	allowed := d.allowedTypes[envelope.Type]
	d.handlersMu.RUnlock()

	if !exists || !allowed {
		d.logger.Warn("Unknown message type",
			"type", envelope.Type,
			"remote", r.RemoteAddr,
		)
		http.Error(w, "Unknown message type", http.StatusBadRequest)
		return
	}

	// LAYER 6: Type-safe dispatch
	if err := handler(ctx, envelope.Payload); err != nil {
		d.metrics.messagesFailed++
		d.logger.Error("Message processing failed",
			"type", envelope.Type,
			"error", err,
		)
		http.Error(w, "Processing failed", http.StatusInternalServerError)
		return
	}

	d.metrics.messagesProcessed++
	d.logger.Info("Message processed successfully",
		"type", envelope.Type,
		"version", envelope.Version,
	)
	w.WriteHeader(http.StatusOK)
}

func main() {
	logger := slog.Default()
	signingKey := []byte("your-256-bit-secret-key-here-min32")

	dispatcher := NewSecureDispatcher(signingKey, logger)

	http.HandleFunc("/api/messages", dispatcher.HandleMessage)
	http.ListenAndServe(":8080", nil)
}
```

**Defense in Depth Layers**:

1. **Body Size Limiting**: `http.MaxBytesReader` prevents memory exhaustion before any parsing occurs

2. **Cryptographic Signature Verification**: HMAC-SHA256 ensures message authenticity and integrity with timestamp to prevent replay attacks

3. **Envelope-Payload Separation**: Parse only the envelope first, validate message type before touching payload

4. **Compile-Time Type Safety**: Generic handlers `handleTypedMessage[T]` ensure each message type is deserialized into its specific struct

5. **Explicit Type Allowlist**: Only pre-registered message types are processed, eliminating dynamic type instantiation

6. **Post-Deserialization Validation**: All fields validated using struct tags after unmarshaling

**Additional Protections**:
- **Context timeouts**: Prevent slow-loris style attacks with `context.WithTimeout`
- **Structured logging**: Full audit trail with `slog` for security monitoring
- **Metrics collection**: Track signature failures and processing errors for anomaly detection
- **DisallowUnknownFields**: Reject messages with unexpected fields to prevent field injection
- **Generic error responses**: Never leak internal error details to callers
- **Constant-time signature comparison**: `hmac.Equal` prevents timing attacks

