    if (!sessionData || !signature) {
      return res.status(400).json({ error: 'Missing required fields' });
    }

    const restoredSession = safeDeserialize(sessionData, signature);
    req.session = restoredSession;

    res.json({ message: 'Session restored', user: restoredSession.username });
  } catch (error) {
    console.error('Session restore failed:', error.message);
    res.status(400).json({ error: 'Invalid session data' });
  }
});

app.listen(3000);
```

**Key Security Controls**:
- **JSON.parse instead of unserialize**: JSON.parse never executes code, only parses data structures
- **HMAC signature verification**: Cryptographically ensures data hasn't been tampered with
- **Schema validation with Ajv**: Strict allowlist of expected properties and types
- **additionalProperties: false**: Rejects any unexpected fields that might contain malicious data

Great question. When you need to serialize complex types beyond JSON's native capabilities, you need a safe serialization strategy with explicit type handling and integrity verification.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const Ajv = require('ajv');
const addFormats = require('ajv-formats');
const crypto = require('crypto');
const winston = require('winston');

const app = express();
app.use(express.json({ limit: '10kb' })); // Limit payload size

// Configure secure logging
const logger = winston.createLogger({
  level: 'info',
  format: winston.format.json(),
  transports: [new winston.transports.File({ filename: 'security.log' })]
});

// Secrets from environment
const HMAC_SECRET = process.env.HMAC_SECRET;
const ENCRYPTION_KEY = Buffer.from(process.env.ENCRYPTION_KEY, 'hex');

// Safe type registry - ALLOWLIST only
const SAFE_TYPES = {
  'Date': {
    serialize: (date) => ({ __type: 'Date', value: date.toISOString() }),
    deserialize: (obj) => {
      const date = new Date(obj.value);
      if (isNaN(date.getTime())) throw new Error('Invalid date');
      return date;
    }
  },
  'Buffer': {
    serialize: (buf) => ({ __type: 'Buffer', value: buf.toString('base64') }),
    deserialize: (obj) => {
      if (obj.value.length > 1000000) throw new Error('Buffer too large');
      return Buffer.from(obj.value, 'base64');
    }
  },
  'Set': {
    serialize: (set) => ({ __type: 'Set', value: Array.from(set) }),
    deserialize: (obj) => {
      if (!Array.isArray(obj.value)) throw new Error('Invalid Set data');
      return new Set(obj.value);
    }
  },
  'Map': {
    serialize: (map) => ({ __type: 'Map', value: Array.from(map.entries()) }),
    deserialize: (obj) => {
      if (!Array.isArray(obj.value)) throw new Error('Invalid Map data');
      return new Map(obj.value);
    }
  }
};

class SecureSerializer {
  constructor(secret, encryptionKey) {
    this.secret = secret;
    this.encryptionKey = encryptionKey;
    this.ajv = new Ajv({ allErrors: true, removeAdditional: true });
    addFormats(this.ajv);
  }

  // Recursively serialize with type preservation
  serializeValue(value, depth = 0) {
    if (depth > 10) throw new Error('Serialization depth exceeded');

    if (value === null || value === undefined) return value;

    // Check registered safe types
    const typeName = value.constructor?.name;
    if (SAFE_TYPES[typeName]) {
      return SAFE_TYPES[typeName].serialize(value);
    }

    if (Array.isArray(value)) {
      return value.map(item => this.serializeValue(item, depth + 1));
    }

    if (typeof value === 'object') {
      const result = {};
      for (const [key, val] of Object.entries(value)) {
        // Reject keys that could be exploited
        if (key.startsWith('__proto__') || key === 'constructor') {
          throw new Error(`Forbidden key: ${key}`);
        }
        result[key] = this.serializeValue(val, depth + 1);
      }
      return result;
    }

    return value;
  }

  // Recursively deserialize with type restoration
  deserializeValue(value, depth = 0) {
    if (depth > 10) throw new Error('Deserialization depth exceeded');

    if (value === null || value === undefined) return value;

    if (Array.isArray(value)) {
      return value.map(item => this.deserializeValue(item, depth + 1));
    }

    if (typeof value === 'object') {
      // Check for typed object
      if (value.__type && typeof value.__type === 'string') {
        const handler = SAFE_TYPES[value.__type];
        if (!handler) {
          throw new Error(`Unknown type: ${value.__type}`);
        }
        return handler.deserialize(value);
      }

      const result = {};
      for (const [key, val] of Object.entries(value)) {
        // Prototype pollution prevention
        if (key === '__proto__' || key === 'constructor' || key === 'prototype') {
          logger.warn('Prototype pollution attempt blocked', { key });
          continue;
        }
        result[key] = this.deserializeValue(val, depth + 1);
      }
      return result;
    }

    return value;
  }

  // Encrypt sensitive data
  encrypt(data) {
    const iv = crypto.randomBytes(16);
    const cipher = crypto.createCipheriv('aes-256-gcm', this.encryptionKey, iv);
    let encrypted = cipher.update(data, 'utf8', 'hex');
    encrypted += cipher.final('hex');
    const authTag = cipher.getAuthTag();
    return {
      iv: iv.toString('hex'),
      data: encrypted,
      tag: authTag.toString('hex')
    };
  }

  // Decrypt and verify
  decrypt(encrypted) {
    const decipher = crypto.createDecipheriv(
      'aes-256-gcm',
      this.encryptionKey,
      Buffer.from(encrypted.iv, 'hex')
    );
    decipher.setAuthTag(Buffer.from(encrypted.tag, 'hex'));
    let decrypted = decipher.update(encrypted.data, 'hex', 'utf8');
    decrypted += decipher.final('utf8');
    return decrypted;
  }

  // Full secure serialization with signing
  serialize(data, schema = null) {
    const serialized = this.serializeValue(data);
    const jsonStr = JSON.stringify(serialized);

    // Optionally encrypt
    const payload = this.encrypt(jsonStr);
    const payloadStr = JSON.stringify(payload);

    // Sign the encrypted payload
    const signature = crypto
      .createHmac('sha256', this.secret)
      .update(payloadStr)
      .digest('hex');

    return {
      payload: payloadStr,
      signature,
      version: 1,
      timestamp: Date.now()
    };
  }

  // Full secure deserialization with verification
  deserialize(envelope, schema = null, maxAge = 3600000) {
    // Verify timestamp (prevent replay attacks)
    if (Date.now() - envelope.timestamp > maxAge) {
      throw new Error('Serialized data has expired');
    }

    // Verify signature
    const expectedSig = crypto
      .createHmac('sha256', this.secret)
      .update(envelope.payload)
      .digest('hex');

    if (!crypto.timingSafeEqual(
      Buffer.from(envelope.signature, 'hex'),
      Buffer.from(expectedSig, 'hex')
    )) {
      throw new Error('Signature verification failed');
    }

    // Decrypt
    const encrypted = JSON.parse(envelope.payload);
    const jsonStr = this.decrypt(encrypted);
    const parsed = JSON.parse(jsonStr);

    // Validate schema if provided
    if (schema) {
      const validate = this.ajv.compile(schema);
      if (!validate(parsed)) {
        throw new Error(`Schema validation failed: ${this.ajv.errorsText(validate.errors)}`);
      }
    }

    // Deserialize with type restoration
    return this.deserializeValue(parsed);
  }
}

// Initialize serializer
const serializer = new SecureSerializer(HMAC_SECRET, ENCRYPTION_KEY);

// Schema for user session
const userSessionSchema = {
  type: 'object',
  properties: {
    userId: { type: 'integer', minimum: 1 },
    username: { type: 'string', maxLength: 50 },
    permissions: { type: 'array', items: { type: 'string' } },
    loginTime: { type: 'object' }, // Will be Date after deserialization
    metadata: { type: 'object' }
  },
  required: ['userId', 'username'],
  additionalProperties: false
};

// API endpoint with full protection
app.post('/api/session/restore', async (req, res) => {
  const startTime = Date.now();
  const clientIP = req.ip;

  try {
    const { envelope } = req.body;

    if (!envelope || !envelope.payload || !envelope.signature) {
      logger.warn('Malformed session restore request', { clientIP });
      return res.status(400).json({ error: 'Invalid request format' });
    }

    const session = serializer.deserialize(envelope, userSessionSchema);

    logger.info('Session restored successfully', {
      userId: session.userId,
      clientIP,
      duration: Date.now() - startTime
    });

    res.json({ success: true, username: session.username });
  } catch (error) {
    logger.error('Session restore failed', {
      error: error.message,
      clientIP,
      duration: Date.now() - startTime
    });

    res.status(400).json({ error: 'Session restoration failed' });
  }
});

app.listen(3000);
```

