Using Go's `gob` encoding for untrusted input is extremely dangerous. While Go doesn't have the same gadget chain vulnerabilities as Java serialization, gob can still lead to denial of service, type confusion attacks, and arbitrary struct population that bypasses validation.

**VULNERABLE CODE**:

```go
package main

import (
	"encoding/gob"
	"log"
	"net/http"
)

type UserConfig struct {
	Username    string
	IsAdmin     bool
	Permissions []string
	Settings    map[string]interface{}
}

func updateConfigHandler(w http.ResponseWriter, r *http.Request) {
	var config UserConfig

	// VULNERABLE: Directly decoding untrusted gob data
	decoder := gob.NewDecoder(r.Body)
	if err := decoder.Decode(&config); err != nil {
		http.Error(w, "Invalid data", http.StatusBadRequest)
		return
	}

	// Attacker can set IsAdmin=true, bypass all authorization
	if config.IsAdmin {
		log.Printf("Admin user %s updating settings", config.Username)
		applyAdminSettings(config)
	} else {
		applyUserSettings(config)
	}

	w.Write([]byte("Config updated"))
}

func applyAdminSettings(config UserConfig) {
	// Privileged operations
}

func applyUserSettings(config UserConfig) {
	// Limited operations
}

func main() {
	http.HandleFunc("/api/config", updateConfigHandler)
	log.Fatal(http.ListenAndServe(":8080", nil))
}
```

